/**
 * absolutely-nothing
 *
 * Type definitions for doing absolutely nothing, correctly typed.
 */

/** Does absolutely nothing. Returns nothing. Guaranteed. */
export declare function absolutelyNothing(): void;

/** Does nothing. Alias for absolutelyNothing, in case that wasn't clear. */
export declare function doNothing(): void;

/** Makes nothing. Successfully. */
export declare function makeNothing(): void;

/** Creates a void. Not the TypeScript kind. Just... void. */
export declare function createVoid(): void;

/** Industry-standard noop. */
export declare function noop(): void;

/** Returns empty. Is empty. */
export declare function empty(): void;

/** Gets nothing. Type-safe nothing. */
export declare function getNothing(): undefined;

/** Still does nothing. Consistently. */
export declare function stillNothing(): void;

/** Async nothing. For modern applications that need to do nothing asynchronously. */
export declare function awaitNothing(): Promise<undefined>;

/** Fixes your code by doing nothing about it. */
export declare function fixYourCode(): void;

/** Improves performance by not adding any overhead. */
export declare function improvePerformance(): void;

/** Solves all your problems. (Results may vary. Results will be undefined.) */
export declare function solveAllProblems(): void;

/** Enterprise-grade nothing. Comes with nothing SLA. */
export declare function enterpriseNothing(): void;

/** Production-ready nothing. Tested in environments where nothing was required. */
export declare function productionReadyNothing(): void;

/** Scales nothing horizontally, vertically, or not at all. */
export declare function scaleNothing(): void;

/** Default export: absolutelyNothing. */
export default absolutelyNothing;
